import psycopg2

def search_users(**kwargs):
    """
    Search users by multiple criteria.

    Parameters
    ----------
    kwargs : dict
        A dictionary of key/value pairs to filter the results on.

    Returns
    -------
    list
        A list of dictionaries containing user information.
    """
    # Connect to PostgreSQL database
    conn = psycopg2.connect(dbname='postgres', user='postgres')
    cur = conn.cursor()

    # Build SQL query based on provided arguments
    sql_query = 'SELECT * FROM users'
    where_clause = []
    for key, value in kwargs.items():
        if not isinstance(value, str):
            raise TypeError('Value must be a string.')

        where_clause.append(f'{key}={value}')

    # Add WHERE clause to SQL query based on provided arguments
    if len(where_clause) > 0:
        sql_query += ' WHERE' + ' AND '.join(where_clause)

    cur.execute(sql_query)
    results = cur.fetchall()

    # Convert results into a list of dictionaries
    users = []
    for row in results:
        user = {}
        for i, column in enumerate(cur.description):
            user[column[0]] = row[i]

        users.append(user)

    return users